/**
 * Sound Library matcher
 *
 * Maps sfxTags (generated by the LLM) and page content keywords
 * to actual Google Sound Library URLs.
 *
 * The CSV is fetched once and cached in memory.
 * URL: https://d2xsxph8kpxj0f.cloudfront.net/310519663399842622/cuoraNs8SGWCiJUcwSXm4W/google-sound-library_03ad0264.csv
 */

export const SOUND_LIBRARY_CSV_URL =
  "https://d2xsxph8kpxj0f.cloudfront.net/310519663399842622/cuoraNs8SGWCiJUcwSXm4W/google-sound-library_03ad0264.csv";

export interface SoundEntry {
  category: string;
  sound: string;
  url: string;
}

// ─── Genre → preferred categories ────────────────────────────────────────────

export const GENRE_SOUND_CATEGORIES: Record<string, string[]> = {
  fairy_tale: ["animals", "ambiences", "human_voices", "cartoon", "weather"],
  comic: ["impacts", "cartoon", "crowds", "transportation", "weapons"],
  crime_mystery: ["ambiences", "doors", "foley", "human_sounds", "weather"],
  fantasy_scifi: ["science_fiction", "ambiences", "impacts", "weather"],
  romance: ["ambiences", "human_voices", "animals", "water"],
  horror_thriller: ["horror", "ambiences", "doors", "weather", "impacts"],
};

