/**
 * Given page content and sfxTags, find the best matching sound URL from the library.
 * entries: parsed CSV rows
 */
export function findBestSound(
  entries: SoundEntry[],
  pageContent: string,
  sfxTags: string[],
  genre: string
): string | null {
  if (entries.length === 0) return null;

  const contentLower = pageContent.toLowerCase();
  const preferredCategories = GENRE_SOUND_CATEGORIES[genre] ?? [];

  // Build candidate list from content keywords
  const candidateFragments: string[] = [];
  for (const { keywords, soundFragments } of CONTENT_KEYWORD_MAP) {
    if (keywords.some(kw => contentLower.includes(kw))) {
      candidateFragments.push(...soundFragments);
    }
  }

  // Also add sfxTags as fragments (split by _ and -)
  for (const tag of sfxTags) {
    candidateFragments.push(...tag.split(/[_-]/));
  }

  // Score each entry
  const scored = entries.map(entry => {
    let score = 0;
    const soundLower = entry.sound.toLowerCase();
    const catLower = entry.category.toLowerCase();

    // Preferred genre category bonus
    if (preferredCategories.includes(catLower)) score += 3;

    // Fragment match bonus
    for (const frag of candidateFragments) {
      if (soundLower.includes(frag.toLowerCase())) score += 5;
    }

    return { entry, score };
  });

  // Sort by score descending, then pick the best
  scored.sort((a, b) => b.score - a.score);

  // Return top match if it has any score, otherwise fall back to genre category
  const best = scored[0];
  if (best && best.score > 0) return best.entry.url;

  // Fallback: pick a random entry from the preferred genre categories
  const fallbacks = entries.filter(e => preferredCategories.includes(e.category));
  if (fallbacks.length > 0) {
    return fallbacks[Math.floor(Math.random() * fallbacks.length)].url;
  }

  return null;
}
